@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput" @bind:after="OnContentChanged"></textarea>

<div class="d-flex align-items-center gap-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private DateTime? lastSavedAt;
    private bool hasUnsavedChanges;
    private System.Timers.Timer? autoSaveTimer;
    private IJSObjectReference? module;

    private const string StorageKeyContent = "notepad-content";
    private const string StorageKeySavedAt = "notepad-savedAt";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>("import", "./Components/Pages/Notepad.razor.js");

        var saved = await module.InvokeAsync<string?>("load", StorageKeyContent);
        if (!string.IsNullOrEmpty(saved))
        {
            content = saved;

            var savedAtStr = await module.InvokeAsync<string?>("load", StorageKeySavedAt);
            if (DateTime.TryParse(savedAtStr, out var parsed))
            {
                lastSavedAt = parsed;
            }

            StateHasChanged();
        }

        autoSaveTimer = new System.Timers.Timer(30_000);
        autoSaveTimer.Elapsed += async (_, _) => await InvokeAsync(AutoSave);
        autoSaveTimer.Start();
    }

    private void OnContentChanged()
    {
        if (!hasUnsavedChanges)
        {
            hasUnsavedChanges = true;
            _ = module?.InvokeVoidAsync("setBeforeUnload", true);
        }
    }

    private async Task AutoSave()
    {
        if (!hasUnsavedChanges) return;
        await Save();
        StateHasChanged();
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Save()
    {
        if (module is null) return;

        await module.InvokeVoidAsync("save", StorageKeyContent, content);
        lastSavedAt = DateTime.Now;
        await module.InvokeVoidAsync("save", StorageKeySavedAt, lastSavedAt.Value.ToString("O"));
        hasUnsavedChanges = false;
        await module.InvokeVoidAsync("setBeforeUnload", false);
    }

    private async Task Clear()
    {
        content = string.Empty;
        lastSavedAt = null;
        hasUnsavedChanges = false;

        if (module is not null)
        {
            await module.InvokeVoidAsync("remove", StorageKeyContent);
            await module.InvokeVoidAsync("remove", StorageKeySavedAt);
            await module.InvokeVoidAsync("setBeforeUnload", false);
        }
    }

    public async ValueTask DisposeAsync()
    {
        autoSaveTimer?.Stop();
        autoSaveTimer?.Dispose();

        if (module is not null)
        {
            await module.InvokeVoidAsync("setBeforeUnload", false);
            await module.DisposeAsync();
        }
    }
}

const beforeUnloadHandler = (e) => {
    e.preventDefault();
};

export function save(key, value) {
    localStorage.setItem(key, value);
}

export function load(key) {
    return localStorage.getItem(key);
}

export function remove(key) {
    localStorage.removeItem(key);
}

export function setBeforeUnload(enable) {
    window.removeEventListener("beforeunload", beforeUnloadHandler);
    if (enable) {
        window.addEventListener("beforeunload", beforeUnloadHandler);
    }
}

